119	    let mut sections: Vec<&str> = Vec::new();
120	    for key in keys {
121	        let (section, _leaf) = section_and_leaf(key.path);
122	        if !sections.contains(&section) {
123	            sections.push(section);
124	        }
125	    }
126	    for section in sections {
127	        info!("[{section}]");
128	        for key in keys {
129	            let (key_section, leaf) = section_and_leaf(key.path);
130	            if key_section != section {
131	                continue;
132	            }
133	            let prefix = if key.required { "" } else { "# " };
134	            let value = render_value(key);
135	            info!("{prefix}{leaf} = {value}   # {}", key.doc);
136	        }
137	    }
138	    info!("");
139	}
